public boolean canBalance(int[] nums)
{

}

Code:
public boolean canBalance(int[] nums) {
    int sum = 0;
    for (int i = 0; i < nums.length; i++) {
        sum += nums[i];
    }

    int leftSum = 0;
    for (int i = 0; i < nums.length; i++) {
        sum -= nums[i];
        if (leftSum == sum) {
            return true;
        }
        leftSum += nums[i];
    }

    return false;
}

